/* ===== error-guard.js ===== */
(function(){
  window.addEventListener('error', function(e){
    try { console.error('[Codivium Landing] Error:', e.message, e.filename, e.lineno, e.colno); } catch (_) {}
  });
  window.addEventListener('unhandledrejection', function(e){
    try { console.error('[Codivium Landing] Unhandled rejection:', e.reason); } catch (_) {}
  });
})();



/* ===== runtime-helpers-bootstrap.js ===== */
(function(){
  if (window.__cvdLandingRuntime) return;
  const isActive = () => !document.hidden;
  function debounce(fn, wait){
    let t;
    return (...args)=>{
      clearTimeout(t);
      t = setTimeout(()=>fn(...args), wait);
    };
  }
  const raf = window.requestAnimationFrame.bind(window);
  function request(fn){
    if (isActive()) return raf(fn);
    const onVis = ()=>{
      if (!document.hidden){
        document.removeEventListener('visibilitychange', onVis);
        raf(fn);
      }
    };
    document.addEventListener('visibilitychange', onVis, { passive: true });
    return null;
  }
  window.__cvdLandingRuntime = { isActive, debounce, raf, request };
})();


