/* ===== 03-inline-3.js ===== */
/***************************************************************
     * Section 1 background: sample the hero image gradient and apply
     * it to the section so the image feels integrated.
     *
     * Works best for local images (same-origin). If the image cannot
     * be sampled (CORS), it silently falls back to the default.
     ***************************************************************/
    (function(){
      
      // --- Codivium Landing runtime guards (A4/A5) ---
      const __cvd_isActive = window.__cvdLandingRuntime.isActive;
      const __cvd_debounce = window.__cvdLandingRuntime.debounce;
      const __cvd_raf = window.__cvdLandingRuntime.raf;
      const __cvd_request = window.__cvdLandingRuntime.request;
const section = document.getElementById("section1");
      const img = section ? section.querySelector(".hero-image img") : null;
      if (!section || !img) return;

      function clamp01(x){ return Math.max(0, Math.min(1, x)); }

      function rgbToCss(c){ return `rgb(${c.r}, ${c.g}, ${c.b})`; }

      function avgColor(ctx, x0, y0, w, h){
        const data = ctx.getImageData(x0, y0, w, h).data;
        let r=0,g=0,b=0,n=0;
        for (let i=0;i<data.length;i+=4){
          const a = data[i+3] / 255;
          // ignore fully transparent pixels
          if (a < 0.02) continue;
          r += data[i] * a;
          g += data[i+1] * a;
          b += data[i+2] * a;
          n += a;
        }
        if (n <= 0.0001) return {r: 3, g: 10, b: 24}; // fallback
        return { r: Math.round(r/n), g: Math.round(g/n), b: Math.round(b/n) };
      }

      function buildGradient(colors){
        // colors: [{stop:0..1, rgb:{r,g,b}}]
        const stops = colors.map(c => `${rgbToCss(c.rgb)} ${Math.round(c.stop*100)}%`).join(", ");
        return `linear-gradient(180deg, ${stops})`;
      }

      function applyFromImage(){
        try{
          const w = img.naturalWidth, h = img.naturalHeight;
          if (!w || !h) return;

          const canvas = document.createElement("canvas");
          const ctx = canvas.getContext("2d", { willReadFrequently: true });
          canvas.width = w;
          canvas.height = h;
          ctx.drawImage(img, 0, 0, w, h);

          // sample a vertical strip (10% width) from the left-middle area
          const stripX = Math.floor(w * 0.08);
          const stripW = Math.max(8, Math.floor(w * 0.10));

          const sampleStops = [0.00, 0.18, 0.38, 0.58, 0.78, 1.00];
          const colors = sampleStops.map((t) => {
            const y = Math.floor(clamp01(t) * (h - 1));
            const y0 = Math.max(0, y - 3);
            const hh = Math.min(7, h - y0);
            const rgb = avgColor(ctx, stripX, y0, stripW, hh);
            return { stop: t, rgb };
          });

          const gradient = buildGradient(colors);

          // apply to section background
          section.style.background = gradient;

          // also apply behind the image container so edges blend better
          const heroBox = section.querySelector(".hero-image");
          if (heroBox){
            heroBox.style.background = gradient;
          }
        } catch (e){
          // Likely CORS/security error, do nothing (fallback to default styles)
        }
      }

      if (img.complete) applyFromImage();
      else img.addEventListener("load", applyFromImage, { once: true });
    })();


/* ===== 04-inline-4.js ===== */
/***************************************************************
     * Section 4 chevrons: click to advance panels (keeps scroll model)
     * - Hide left chevron on first panel
     * - Hide right chevron on last panel
     ***************************************************************/
    (function(){
      
      // --- Codivium Landing runtime guards (A4/A5) ---
      const __cvd_isActive = window.__cvdLandingRuntime.isActive;
      const __cvd_debounce = window.__cvdLandingRuntime.debounce;
      const __cvd_raf = window.__cvdLandingRuntime.raf;
      const __cvd_request = window.__cvdLandingRuntime.request;
const spacer = document.getElementById("hSpacer");
      const windowEl = document.getElementById("hWindow");
      const leftBtn = document.querySelector("#section4 .scroll-hint.left");
      const rightBtn = document.querySelector("#section4 .scroll-hint.right");
      if (!spacer || !windowEl || !leftBtn || !rightBtn) return;

      const scrollRoot = document.scrollingElement || document.documentElement;
      const panels = Math.max(1, document.querySelectorAll("#section4 .h-track > .h-panel").length || 5);

      function clamp(n,a,b){ return Math.max(a, Math.min(b,n)); }
      function getScrollTop(){
        return scrollRoot ? scrollRoot.scrollTop : (window.scrollY || window.pageYOffset || 0);
      }
      function getSectionStart(){
        return getScrollTop() + spacer.getBoundingClientRect().top;
      }
      function setScrollTop(top){
        const nextTop = Math.max(0, top);
        if (scrollRoot && typeof scrollRoot.scrollTo === "function") {
          scrollRoot.scrollTo({ top: nextTop, behavior: "smooth" });
          return;
        }
        window.scrollTo({ top: nextTop, behavior: "smooth" });
      }

      function getState(){
        const viewportH = window.innerHeight;
        const total = Math.max(0, spacer.offsetHeight - viewportH);
        const sectionStart = getSectionStart();
        const scrolled = clamp(getScrollTop() - sectionStart, 0, total);
        const progress = total > 0 ? (scrolled / total) : 0;
        return { total, scrolled, progress };
      }

      function progressToIndex(progress){
        // Tuned for a more responsive soft snap so one wheel gesture can
        // advance a panel sooner instead of requiring several partial scrolls.

        if (panels <= 1) return 0;
        const raw = clamp(progress, 0, 1) * (panels - 1);
        const base = Math.floor(raw);
        const frac = raw - base;
        const SNAP_THRESHOLD = 0.10;
        return clamp(base + (frac >= SNAP_THRESHOLD ? 1 : 0), 0, panels - 1);
      }

      function currentIndex(){
        const { progress } = getState();
        return progressToIndex(progress);
      }

      function updateChevronVisibility(){
        const idx = currentIndex();
        leftBtn.style.display = (idx <= 0) ? "none" : "grid";
        rightBtn.style.display = (idx >= panels - 1) ? "none" : "grid";
      }

      function goToPanel(delta){
        const stepW = Math.max(1, lastStep || Math.round(windowEl.clientWidth || 1));
        const maxTrackX = Math.max(0, (panels - 1) * stepW);

        const { total, progress, scrolled } = getState();
        const idx = progressToIndex(progress);
        const nextIdx = clamp(idx + delta, 0, panels - 1);

        const nextX = nextIdx * stepW;
        const nextProgress = maxTrackX > 0 ? (nextX / maxTrackX) : 0;
        const nextScroll = nextProgress * total;

        setScrollTop(getScrollTop() + (nextScroll - scrolled));
      }

      leftBtn.addEventListener("click", ()=> goToPanel(-1));
      rightBtn.addEventListener("click", ()=> goToPanel(1));

      
      let __cvd_pending = false;
      function scheduleUpdate(){
        if (__cvd_pending) return;
        __cvd_pending = true;
        __cvd_request(()=>{
          __cvd_pending = false;
          updateChevronVisibility();
        });
      }

      let __cvd_inView = true;
      if ("IntersectionObserver" in window){
        const io = new IntersectionObserver((entries)=>{
          __cvd_inView = entries.some(e => e.isIntersecting);
          if (__cvd_inView) scheduleUpdate();
        }, { root: null, threshold: 0.01 });
        io.observe(spacer);
      }

      window.addEventListener("scroll", ()=>{ if (__cvd_inView) scheduleUpdate(); }, { passive:true });
      window.addEventListener("resize", __cvd_debounce(()=>{ if (__cvd_inView) scheduleUpdate(); }, 120), { passive:true });

      scheduleUpdate();
})();


/* ===== 06-inline-6.js ===== */
/***************************************************************
     * Flow special arrow: from first icon window -> first side micro-window
     * Path is orthogonal: go LEFT from icon, then DOWN to micro-window.
     ***************************************************************/
    (function(){
      
      // --- Codivium Landing runtime guards (A4/A5) ---
      const __cvd_isActive = window.__cvdLandingRuntime.isActive;
      const __cvd_debounce = window.__cvdLandingRuntime.debounce;
      const __cvd_raf = window.__cvdLandingRuntime.raf;
      const __cvd_request = window.__cvdLandingRuntime.request;
const section = document.getElementById("section2b");
      if (!section) return;

      const steps = section.querySelector(".flow-steps");
      const icon1 = section.querySelector(".flow-iconcard");
      const micro2 = section.querySelector(".flow-sidecard"); // first side micro-window (2nd micro overall)
      const svg = document.getElementById("flowSpecialArrow");
      const path = document.getElementById("flowSpecialPath");
      if (!steps || !icon1 || !micro2 || !svg || !path) return;

      function draw(){
        const box = steps.getBoundingClientRect();
        const a = icon1.getBoundingClientRect();
        const b = micro2.getBoundingClientRect();

        // SVG coordinate space == steps box
        const w = Math.max(1, box.width);
        const h = Math.max(1, box.height);
        svg.setAttribute("viewBox", `0 0 ${w} ${h}`);

        // Start at left-middle of icon
        const x1 = (a.left - box.left);
        const y1 = (a.top - box.top) + (a.height / 2);

        // End at center of micro-window
        const x2 = (b.left - box.left) + (b.width / 2);
        const y2 = (b.top - box.top) + (b.height / 2);

        // Orthogonal: left then down (H then V)
        const d = `M ${x1} ${y1} H ${x2} V ${y2}`;
        path.setAttribute("d", d);
      }
      let __cvd_pending = false;
      function scheduleDraw(){
        if (__cvd_pending) return;
        __cvd_pending = true;
        __cvd_request(()=>{
          __cvd_pending = false;
          draw();
        });
      }

      // Only draw when section is in view (saves work)
      let __cvd_inView = true;
      if ("IntersectionObserver" in window){
        const io = new IntersectionObserver((entries)=>{
          __cvd_inView = entries.some(e => e.isIntersecting);
          if (__cvd_inView) scheduleDraw();
        }, { root: null, threshold: 0.01 });
        io.observe(section);
      }

      const ro = new ResizeObserver(()=>{ if (__cvd_inView) scheduleDraw(); });
      ro.observe(steps);
      window.addEventListener("resize", ()=>{ if (__cvd_inView) scheduleDraw(); }, { passive: true });
      window.addEventListener("scroll", ()=>{ if (__cvd_inView) scheduleDraw(); }, { passive: true });

      scheduleDraw();
})();


/* ===== 07-inline-7.js ===== */
/***************************************************************
     * Flow arrows (Section "How does it work?")
     * Draws:
     *  - Top micro window -> top icon window (vertical)
     *  - Side windows -> corresponding icon windows (horizontal)
     *  - Icon window -> next icon window (vertical)
     *
     * NOTE: Uses SVG-space coordinates (via svg.getBoundingClientRect())
     * and an expanded SVG overlay so arrows are fully visible.
     ***************************************************************/
    (function(){
      
      // --- Codivium Landing runtime guards (A4/A5) ---
      const __cvd_isActive = window.__cvdLandingRuntime.isActive;
      const __cvd_debounce = window.__cvdLandingRuntime.debounce;
      const __cvd_raf = window.__cvdLandingRuntime.raf;
      const __cvd_request = window.__cvdLandingRuntime.request;
const section = document.getElementById("section2b");
      if (!section) return;

      const svg = document.getElementById("flowArrowSvg");
      const steps = section.querySelector(".flow-steps");
      if (!svg || !steps) return;

      const topMicro = section.querySelector(".flow-topmicro");
      const iconCards = Array.from(section.querySelectorAll(".flow-step .flow-iconcard")).slice(0, 5);
      const sideWins  = Array.from(section.querySelectorAll(".flow-step .flow-sidewin")).slice(0, 5);

      
      let __cvd_pathPool = [];
      function resetPaths(){
        // keep pool, just detach all existing paths from svg
        __cvd_pathPool.forEach(p => {
          if (p.parentNode === svg) svg.removeChild(p);
        });
      }
      function usePath(i, d){
        let p = __cvd_pathPool[i];
        if (!p){
          p = document.createElementNS("http://www.w3.org/2000/svg", "path");
          p.setAttribute("class", "flow-arrowpath");
          p.setAttribute("marker-end", "url(#flowArrowHeadGold)");
          __cvd_pathPool[i] = p;
        }
        p.setAttribute("d", d);
        svg.appendChild(p);
      }
function draw(){
        const s = svg.getBoundingClientRect();
        const w = Math.max(1, s.width);
        const h = Math.max(1, s.height);
        svg.setAttribute("viewBox", `0 0 ${w} ${h}`);

        resetPaths();
        let __cvd_pi = 0;

        // DOM rect -> SVG local coordinates helpers
        const xMid = (r) => (r.left - s.left) + (r.width / 2);
        const yMid = (r) => (r.top  - s.top ) + (r.height / 2);
        const xL   = (r) => (r.left - s.left);
        const xR   = (r) => (r.left - s.left) + r.width;
        const yTop = (r) => (r.top  - s.top );
        const yBot = (r) => (r.top  - s.top ) + r.height;

        // Top micro -> first icon (vertical)
        if (topMicro && iconCards[0]){
          const a = topMicro.getBoundingClientRect();
          const b = iconCards[0].getBoundingClientRect();

          const x = xMid(b);
          usePath(__cvd_pi++, `M ${x} ${yBot(a)} V ${yTop(b)}`);
        }

        // Side window -> icon (horizontal)
        for (let i = 0; i < Math.min(iconCards.length, sideWins.length); i++){
          const icon = iconCards[i].getBoundingClientRect();
          const win  = sideWins[i].getBoundingClientRect();

          const y = yMid(win);

          const winIsLeft  = win.right <= icon.left;
          const winIsRight = win.left  >= icon.right;

          if (winIsLeft){
            usePath(__cvd_pi++, `M ${xR(win)} ${y} H ${xL(icon)}`);
          } else if (winIsRight){
            usePath(__cvd_pi++, `M ${xL(win)} ${y} H ${xR(icon)}`);
          }
        }

        // Icon -> next icon (vertical)
        for (let i = 0; i < iconCards.length - 1; i++){
          const a = iconCards[i].getBoundingClientRect();
          const b = iconCards[i+1].getBoundingClientRect();

          const x = xMid(a);
          usePath(__cvd_pi++, `M ${x} ${yBot(a)} V ${yTop(b)}`);
        }
      }

      
      let __cvd_pending = false;
      function scheduleDraw(){
        if (__cvd_pending) return;
        __cvd_pending = true;
        __cvd_request(()=>{
          __cvd_pending = false;
          draw();
        });
      }

      // Redraw on scroll/resize/element resize, but only when section is visible
      let __cvd_inView = true;
      if ("IntersectionObserver" in window){
        const io = new IntersectionObserver((entries)=>{
          __cvd_inView = entries.some(e => e.isIntersecting);
          if (__cvd_inView) scheduleDraw();
        }, { root: null, threshold: 0.01 });
        io.observe(section);
      }

      const ro = new ResizeObserver(()=>{ if (__cvd_inView) scheduleDraw(); });
      ro.observe(steps);
      if (topMicro) ro.observe(topMicro);
      iconCards.forEach(el => ro.observe(el));
      sideWins.forEach(el => ro.observe(el));

      window.addEventListener("resize", ()=>{ if (__cvd_inView) scheduleDraw(); }, { passive: true });
      window.addEventListener("scroll", ()=>{ if (__cvd_inView) scheduleDraw(); }, { passive: true });

      scheduleDraw();
      setTimeout(()=>{ if (__cvd_inView) scheduleDraw(); }, 140);
      setTimeout(()=>{ if (__cvd_inView) scheduleDraw(); }, 320);
})();


