/* ===== 09-inline-9.js ===== */
/***************************************************************
     * Horizontal scroll logic (soft snap horizontal stepping)
     * Drives the transform of #hTrack based on vertical scroll.
     ***************************************************************/
    (function(){
      
      // --- Codivium Landing runtime guards (A4/A5) ---
      const __cvd_isActive = window.__cvdLandingRuntime.isActive;
      const __cvd_debounce = window.__cvdLandingRuntime.debounce;
      const __cvd_raf = window.__cvdLandingRuntime.raf;
      const __cvd_request = window.__cvdLandingRuntime.request;
const spacer = document.getElementById("hSpacer");
      const track  = document.getElementById("hTrack");
      const windowEl = document.getElementById("hWindow");
      if (!spacer || !track || !windowEl) return;

      const scrollRoot = document.scrollingElement || document.documentElement;
      let currentX = 0;
      let targetX  = 0;
      let maxX     = 0;
      let panelCount = 0;
      let lastWidth = 0;
      let lastStep = 0;

      function clamp(n, a, b){ return Math.max(a, Math.min(b, n)); }
      function lerp(a, b, t){ return a + (b - a) * t; }
      function getPanels(){
        return Array.from(track.children).filter((el) => el.classList && el.classList.contains("h-panel"));
      }
      function getScrollTop(){
        return scrollRoot ? scrollRoot.scrollTop : (window.scrollY || window.pageYOffset || 0);
      }
      function getSectionStart(){
        return getScrollTop() + spacer.getBoundingClientRect().top;
      }

      function recalc(force){
        const panelEls = getPanels();
        panelCount = Math.max(1, panelEls.length || 5);

        const rect = windowEl.getBoundingClientRect();
        const w = Math.round(rect.width || windowEl.clientWidth || 0);
        if (!w) return false;

        // Geometry tuned so the previous/next panel edges remain clearly visible
        // while the active panel stays centered.
        const peek = Math.max(56, Math.min(156, Math.round(w * 0.135)));
        const gap = Math.max(4, Math.min(14, Math.round(w * 0.006)));
        const panelW = Math.max(1, w - (peek * 2));
        const stepW = panelW + gap;
        const newMaxX = Math.max(0, (panelCount - 1) * stepW);

        if (!force && w === lastWidth && newMaxX === maxX && stepW === lastStep) return true;

        lastWidth = w;
        lastStep = stepW;
        maxX = newMaxX;

        track.style.width = `${(peek * 2) + (panelCount * panelW) + ((panelCount - 1) * gap)}px`;
        track.style.paddingLeft = `${peek}px`;
        track.style.paddingRight = `${peek}px`;
        track.style.columnGap = `${gap}px`;
        panelEls.forEach((panel) => {
          panel.style.flex = `0 0 ${panelW}px`;
          panel.style.width = `${panelW}px`;
          panel.style.minWidth = `${panelW}px`;
          panel.style.maxWidth = `${panelW}px`;
        });

        const stepScroll = Math.max(72, Math.round(window.innerHeight * 0.22));
        const requiredHeight = Math.max(
          Math.round(window.innerHeight * 1.12),
          Math.round(window.innerHeight + ((panelCount - 1) * stepScroll))
        );
        spacer.style.height = `${Math.ceil(requiredHeight)}px`;
        return true;
      }

      function progressToIndex(progress){
        if (panelCount <= 1) return 0;
        const raw = clamp(progress, 0, 1) * (panelCount - 1);
        const base = Math.floor(raw);
        const frac = raw - base;
        const SNAP_THRESHOLD = 0.10;
        return clamp(base + (frac >= SNAP_THRESHOLD ? 1 : 0), 0, panelCount - 1);
      }

      function updatePanelDepth(activeIndex){
        const panelEls = getPanels();
        panelEls.forEach((panel, idx) => {
          panel.classList.remove("is-active", "is-prev", "is-next", "is-far");
          if (idx === activeIndex){
            panel.classList.add("is-active");
          } else if (idx === activeIndex - 1){
            panel.classList.add("is-prev");
          } else if (idx === activeIndex + 1){
            panel.classList.add("is-next");
          } else {
            panel.classList.add("is-far");
          }
        });
      }

      function computeTargetFromScroll(){
        if (!recalc(false)) return;
        const viewportH = window.innerHeight;
        const sectionStart = getSectionStart();
        const total = Math.max(1, spacer.offsetHeight - viewportH);
        const scrolled = clamp(getScrollTop() - sectionStart, 0, total);
        const progress = total > 0 ? (scrolled / total) : 0;
        const activeIndex = progressToIndex(progress);
        targetX = activeIndex * lastStep;
        updatePanelDepth(activeIndex);
      }

      
      let __cvd_running = false;
      function animate(){
        __cvd_running = true;
        currentX = lerp(currentX, targetX, 0.36);

        // Snap when extremely close (prevents endless tiny updates)
        const delta = Math.abs(targetX - currentX);
        if (delta < 0.18) currentX = targetX;

        track.style.transform = `translate3d(${-currentX}px,0,0)`;

        // Keep animating only while we still have meaningful movement
        if (Math.abs(targetX - currentX) >= 0.18){
          __cvd_request(animate);
        } else {
          __cvd_running = false;
        }
      }

      function ensureAnimating(){
        if (!__cvd_running){
          __cvd_request(animate);
        }
      }

      let __cvd_inView = true;
      if ("IntersectionObserver" in window){
        const io = new IntersectionObserver((entries)=>{
          __cvd_inView = entries.some(e => e.isIntersecting);
          if (__cvd_inView){
            computeTargetFromScroll();
            ensureAnimating();
          }
        }, { root: null, threshold: 0.01 });
        io.observe(spacer);
      }

      let __cvd_scrollPending = false;
      function onScroll(){
        if (!__cvd_inView) return;
        if (__cvd_scrollPending) return;
        __cvd_scrollPending = true;
        __cvd_request(()=>{
          __cvd_scrollPending = false;
          computeTargetFromScroll();
          ensureAnimating();
        });
      }
      window.addEventListener("scroll", onScroll, { passive:true });

      window.addEventListener("resize", __cvd_debounce(()=>{
        recalc();
        computeTargetFromScroll();
        if (typeof window.constellationResize === "function") window.constellationResize();
        if (__cvd_inView) ensureAnimating();
      }, 120), { passive:true });
recalc();
      computeTargetFromScroll();
      ensureAnimating();
})();

